import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip,
  Legend, ResponsiveContainer,
} from 'recharts';
import api from '../services/api';
import ErrorBoundary from './ErrorBoundary';
import MeasurementPanel from './MeasurementPanel';
import ReportModal from './ReportModal';

function EditModal({ patient, onClose, onSaved }) {
  const [form, setForm] = useState({ ...patient });
  const [error, setError] = useState('');
  const [saving, setSaving] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const res = await api.put(`/patients/${patient.id}`, form);
      onSaved(res.data);
      onClose();
    } catch (err) {
      setError(err.response?.data?.error || 'Update failed.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <h2>Edit Patient</h2>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          {error && <div className="alert alert-error">{error}</div>}
          <form id="edit-form" onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Full Name</label>
              <input className="form-input" value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} required />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Height (cm)</label>
                <input className="form-input" type="number" value={form.height_cm} onChange={e => setForm(f => ({ ...f, height_cm: e.target.value }))} required />
              </div>
              <div className="form-group">
                <label className="form-label">Age</label>
                <input className="form-input" type="number" value={form.age} onChange={e => setForm(f => ({ ...f, age: e.target.value }))} required />
              </div>
            </div>
            <div className="form-group">
              <label className="form-label">Sex</label>
              <select className="form-select" value={form.is_male ? 'male' : 'female'} onChange={e => setForm(f => ({ ...f, is_male: e.target.value === 'male' }))}>
                <option value="male">Male</option>
                <option value="female">Female</option>
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Bale Chat ID</label>
              <input className="form-input" value={form.bale_chat_id || ''} onChange={e => setForm(f => ({ ...f, bale_chat_id: e.target.value }))} placeholder="Optional" />
            </div>
          </form>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" form="edit-form" type="submit" disabled={saving}>
            {saving ? <><span className="spinner" /> Saving…</> : 'Save Changes'}
          </button>
        </div>
      </div>
    </div>
  );
}

function ExportMenu({ patientId }) {
  const [open, setOpen] = useState(false);
  const download = (fmt) => {
    const token = localStorage.getItem('jwt_token');
    const url = `/api/patients/${patientId}/export?format=${fmt}`;
    const a = document.createElement('a');
    a.href = url;
    a.setAttribute('download', '');
    document.body.appendChild(a);
    fetch(url, { headers: { Authorization: `Bearer ${token}` } })
      .then(r => r.blob())
      .then(blob => {
        const burl = URL.createObjectURL(blob);
        a.href = burl;
        a.click();
        URL.revokeObjectURL(burl);
        document.body.removeChild(a);
      });
    setOpen(false);
  };
  return (
    <div style={{ position: 'relative' }}>
      <button className="btn btn-ghost" onClick={() => setOpen(v => !v)}>📥 Export ▾</button>
      {open && (
        <div style={{ position: 'absolute', top: '100%', right: 0, background: '#fff', border: '1px solid var(--gray-200)', borderRadius: 'var(--radius)', boxShadow: 'var(--shadow-md)', zIndex: 10, minWidth: 140 }}>
          <button className="btn btn-ghost" style={{ width: '100%', justifyContent: 'flex-start', borderRadius: 0 }} onClick={() => download('csv')}>📄 CSV</button>
          <button className="btn btn-ghost" style={{ width: '100%', justifyContent: 'flex-start', borderRadius: 0 }} onClick={() => download('excel')}>📊 Excel</button>
        </div>
      )}
    </div>
  );
}

const CHART_LINES = [
  { key: 'weight',       name: 'Weight (kg)',    color: '#2b6cb0', yAxis: 'left'  },
  { key: 'body_fat_pct', name: 'Body Fat (%)',   color: '#fc8181', yAxis: 'right' },
  { key: 'muscle_mass',  name: 'Muscle (kg)',    color: '#48bb78', yAxis: 'left'  },
  { key: 'water_kg',     name: 'Water (kg)',     color: '#63b3ed', yAxis: 'left'  },
];

export default function PatientProfile({ socket }) {
  const { id } = useParams();
  const navigate = useNavigate();
  const [patient, setPatient] = useState(null);
  const [measurements, setMeasurements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState('overview');
  const [showEdit, setShowEdit] = useState(false);
  const [showReport, setShowReport] = useState(false);
  const [selectedMetrics, setSelectedMetrics] = useState({ weight: true, body_fat_pct: true, muscle_mass: false, water_kg: false });

  const load = useCallback(async () => {
    try {
      const [pRes, mRes] = await Promise.all([
        api.get(`/patients/${id}`),
        api.get(`/patients/${id}/measurements`),
      ]);
      setPatient(pRes.data);
      setMeasurements(mRes.data);
    } catch {
      navigate('/patients');
    } finally {
      setLoading(false);
    }
  }, [id, navigate]);

  useEffect(() => { load(); }, [load]);

  const onNewMeasurement = (m) => {
    setMeasurements(prev => [...prev, m]);
  };

  if (loading) return <div className="flex-center" style={{ height: 300 }}><span className="spinner" /></div>;
  if (!patient) return null;

  const chartData = measurements.map(m => ({
    date: new Date(m.recorded_at).toLocaleDateString(),
    weight: m.weight,
    body_fat_pct: m.body_fat_pct,
    muscle_mass: m.muscle_mass,
    water_kg: m.water_kg,
  }));

  const firstWeight = measurements[0]?.weight;
  const lastWeight = measurements[measurements.length - 1]?.weight;
  const totalLoss = firstWeight && lastWeight ? (firstWeight - lastWeight).toFixed(1) : null;

  return (
    <ErrorBoundary>
      {showEdit && (
        <EditModal
          patient={patient}
          onClose={() => setShowEdit(false)}
          onSaved={(p) => setPatient(p)}
        />
      )}
      {showReport && (
        <ReportModal
          patient={patient}
          measurements={measurements}
          onClose={() => setShowReport(false)}
        />
      )}

      {/* Header */}
      <div className="card mb-20">
        <div className="flex-between">
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            <button className="btn btn-ghost btn-sm" onClick={() => navigate('/patients')}>← Back</button>
            <div>
              <h2 style={{ fontSize: 20, fontWeight: 700 }}>{patient.name}</h2>
              <span className="text-muted">
                {patient.age} yrs · {patient.height_cm} cm · {patient.is_male ? 'Male' : 'Female'}
                {patient.bale_chat_id && <> · 📲 Bale linked</>}
              </span>
            </div>
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            <ExportMenu patientId={patient.id} />
            <button className="btn btn-ghost" onClick={() => setShowEdit(true)}>✏️ Edit</button>
            <button className="btn btn-primary" onClick={() => setShowReport(true)} disabled={!patient.bale_chat_id}>
              📊 Report & Send
            </button>
          </div>
        </div>

        {totalLoss !== null && (
          <div style={{ marginTop: 16, display: 'flex', gap: 24 }}>
            <div><span className="text-muted">Starting weight:</span> <strong>{firstWeight} kg</strong></div>
            <div><span className="text-muted">Current weight:</span> <strong>{lastWeight} kg</strong></div>
            <div>
              <span className="text-muted">Total loss:</span>{' '}
              <strong style={{ color: parseFloat(totalLoss) > 0 ? 'var(--green)' : 'var(--red)' }}>
                {totalLoss > 0 ? '−' : '+'}{Math.abs(totalLoss)} kg
              </strong>
            </div>
            <div><span className="text-muted">Visits:</span> <strong>{measurements.length}</strong></div>
          </div>
        )}
      </div>

      {/* Tabs */}
      <div className="tabs">
        {['overview', 'measure', 'history'].map(t => (
          <button key={t} className={`tab-btn ${tab === t ? 'active' : ''}`} onClick={() => setTab(t)}>
            {{ overview: '📊 Overview', measure: '⚖️ Measure', history: '📋 History' }[t]}
          </button>
        ))}
      </div>

      {/* Overview */}
      {tab === 'overview' && (
        <>
          {measurements.length < 2 ? (
            <div className="card">
              <div className="empty-state">
                <div className="empty-state-icon">📊</div>
                <h3>Not enough data</h3>
                <p>At least 2 measurements needed to show charts.</p>
                <button className="btn btn-primary mt-12" onClick={() => setTab('measure')}>Take First Measurement</button>
              </div>
            </div>
          ) : (
            <div className="card">
              <div className="flex-between mb-16">
                <span className="card-title" style={{ marginBottom: 0 }}>Progress Chart</span>
                <div style={{ display: 'flex', gap: 10 }}>
                  {CHART_LINES.map(l => (
                    <label key={l.key} className="checkbox-label">
                      <input
                        type="checkbox"
                        checked={selectedMetrics[l.key]}
                        onChange={e => setSelectedMetrics(prev => ({ ...prev, [l.key]: e.target.checked }))}
                      />
                      <span style={{ color: l.color }}>{l.name}</span>
                    </label>
                  ))}
                </div>
              </div>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={chartData} margin={{ top: 5, right: 20, left: 0, bottom: 5 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--gray-200)" />
                    <XAxis dataKey="date" tick={{ fontSize: 11 }} />
                    <YAxis yAxisId="left" tick={{ fontSize: 11 }} />
                    <YAxis yAxisId="right" orientation="right" tick={{ fontSize: 11 }} />
                    <Tooltip />
                    <Legend />
                    {CHART_LINES.filter(l => selectedMetrics[l.key]).map(l => (
                      <Line
                        key={l.key}
                        yAxisId={l.yAxis}
                        type="monotone"
                        dataKey={l.key}
                        name={l.name}
                        stroke={l.color}
                        strokeWidth={2}
                        dot={{ r: 4 }}
                        activeDot={{ r: 6 }}
                        connectNulls
                      />
                    ))}
                  </LineChart>
                </ResponsiveContainer>
              </div>
            </div>
          )}
        </>
      )}

      {/* Measure */}
      {tab === 'measure' && (
        <MeasurementPanel patient={patient} socket={socket} onMeasurementReady={onNewMeasurement} />
      )}

      {/* History */}
      {tab === 'history' && (
        <div className="card">
          <div className="card-title">Measurement History</div>
          {measurements.length === 0 ? (
            <div className="empty-state" style={{ padding: '30px 0' }}>
              <p>No measurements yet.</p>
            </div>
          ) : (
            <div className="table-wrapper">
              <table>
                <thead>
                  <tr>
                    <th>Date</th>
                    <th>Weight (kg)</th>
                    <th>Body Fat (%)</th>
                    <th>Fat Mass (kg)</th>
                    <th>Muscle (kg)</th>
                    <th>Water (kg)</th>
                    <th>Notes</th>
                  </tr>
                </thead>
                <tbody>
                  {[...measurements].reverse().map(m => (
                    <tr key={m.id}>
                      <td>{new Date(m.recorded_at).toLocaleString()}</td>
                      <td><strong>{m.weight}</strong></td>
                      <td>{m.body_fat_pct ?? '—'}</td>
                      <td>{m.fat_mass ?? '—'}</td>
                      <td>{m.muscle_mass ?? '—'}</td>
                      <td>{m.water_kg ?? '—'}</td>
                      <td className="text-muted">{m.notes || '—'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}
    </ErrorBoundary>
  );
}
